// ─── MAIN ────────────────────────────────────────────────────────────────────
export default function ScienceGame() {
  // ── Screen / meta ──
  const [screen,   setScreen]  = useState("menu");   // menu | loading | playing | roundover | shop
  const [round,    setRound]   = useState(1);
  const [totalEP,  setTotalEP] = useState(0);
  const [bankEP,   setBankEP]  = useState(0);
  const [highScore,setHS]      = useState(0);


  // ── Upgrades ──
  const [upgrades, setUpgrades] = useState({
    timer:0, crit:0, streak:0, shield:0, eliminate:0, freeze:0, multiplier:0, hint:0,
  });

  // ── Round timer ──
  const maxTime = ROUND_BASE_TIME + upgrades.timer * 5;
  const [timeLeft,  setTimeLeft]  = useState(maxTime);
  const [frozen,    setFrozen]    = useState(false);
  const timerRef = useRef(null);

  // ── Question pool ──
  const [pool,        setPool]       = useState([]);
  const [poolIdx,     setPoolIdx]    = useState(0);
  const [usedQs,      setUsedQs]     = useState([]);

  // ── Per-question state ──
  const [selected,    setSelected]  = useState(null);  // null = unanswered
  const [showFeedback,setSF]        = useState(false);
  const [eliminated,  setElim]      = useState(null);
  const [hintActive,  setHintA]     = useState(false);

  // ── Per-round consumables ──
  const [shieldUsed,  setShU]  = useState(false);
  const [elimUsed,    setElU]  = useState(false);
  const [freezeUsed,  setFrU]  = useState(false);
  const [hintUsed,    setHiU]  = useState(false);

  // ── Round stats ──
  const [roundScore,  setRS]    = useState(0);
  const [qAnswered,   setQA]    = useState(0);   // questions attempted this round
  const [qCorrect,    setQC]    = useState(0);
  const [streak,      setStreak]= useState(0);
  const [combo,       setCombo] = useState(0);
  const [roundLog,    setLog]   = useState([]);  // [{correct,pts,crit,topic}]

  // ── Score pops ──
  const [pops, setPops] = useState([]);
  const popId = useRef(0);

  const q = pool[poolIdx];

  // ─── Timer ───────────────────────────────────────────────────────────────
  useEffect(() => {
    if (screen !== "playing") return;
    timerRef.current = setInterval(() => {
      if (frozen) return;
      setTimeLeft(t => {
        if (t <= 0.05) {
          clearInterval(timerRef.current);
          endRound();
          return 0;
        }
        return t - 0.05;
      });
    }, 50);
    return () => clearInterval(timerRef.current);
  }, [screen, frozen]);



  const addPop = (text, x, y, opts={}) => {
    const id = popId.current++;
    setPops(p => [...p, { id, text, x, y, ...opts }]);
    setTimeout(() => setPops(p => p.filter(pp => pp.id !== id)), 1100);
  };

  // ─── Advance to next question ─────────────────────────────────────────────
  const nextQuestion = (currentPoolIdx) => {
    const next = currentPoolIdx + 1;
    if (next >= pool.length) {
      // Pool exhausted mid-round — wrap around (shuffle again)
      setPoolIdx(0);
    } else {
      setPoolIdx(next);
    }
    setSelected(null);
    setSF(false);
    setElim(null);
    setHintA(false);
  };

  // ─── Answer handler ───────────────────────────────────────────────────────
  const answer = (idx) => {
    if (selected !== null || !q) return;
    setSelected(idx);
    setSF(true);

    const ok   = idx === q.answer;
    const mult = 1 + upgrades.multiplier * 0.25;
    const cx   = window.innerWidth  * 0.5;
    const cy   = 200;

    // Shield
    if (!ok && upgrades.shield > 0 && !shieldUsed) {
      setShU(true);
      addPop("🛡 SHIELDED!", cx - 55, cy);
      setQA(n=>n+1);
      setLog(l=>[...l,{correct:false,pts:0,shielded:true,topic:q.topic}]);
      setTimeout(() => nextQuestion(poolIdx), BRIEF_FEEDBACK + 200);
      return;
    }

    if (ok) {
      const base   = 10 * q.difficulty;
      const tBonus = Math.round(timeLeft * 0.8);
      const sBonus = upgrades.streak > 0 ? streak * upgrades.streak * 3 : 0;
      const isCrit = Math.random() < upgrades.crit * 0.1;
      const raw    = (base + tBonus + sBonus) * mult;
      const pts    = Math.round(isCrit ? raw * 2 : raw);
      const nStreak = streak + 1, nCombo = combo + 1;

      setStreak(nStreak); setCombo(nCombo);
      setRS(s=>s+pts); setTotalEP(t=>t+pts); setBankEP(b=>b+pts);
      setQA(n=>n+1); setQC(n=>n+1);
      setLog(l=>[...l,{correct:true,pts,crit:isCrit,topic:q.topic}]);

      if (isCrit) addPop(`⚡ CRIT! +${pts}`, cx-40, cy, {crit:true});
      else        addPop(`+${pts}`, cx, cy);
      if (nCombo >= 3) addPop(`🔥 ×${nCombo} COMBO`, cx-35, cy+40);
    } else {
      setStreak(0); setCombo(0);
      setQA(n=>n+1);
      setLog(l=>[...l,{correct:false,pts:0,topic:q.topic,question:q.q,options:q.options,correctIdx:q.answer,chosenIdx:idx,explanation:q.explanation}]);
      addPop("✗", cx, cy, {miss:true});
    }

    // Show feedback briefly then advance
    const delay = ok ? BRIEF_FEEDBACK : BRIEF_FEEDBACK + 200;
    setTimeout(() => nextQuestion(poolIdx), delay);
  };

  // ─── End of round ─────────────────────────────────────────────────────────
  const endRound = () => {
    clearInterval(timerRef.current);
    setUsedQs(u => [...u, ...pool]);
    setHS(h => Math.max(h, totalEP));
    setScreen("summary");
  };

  // ─── Start round ──────────────────────────────────────────────────────────
  const beginRound = async (rnd, _unused) => {
    setScreen("loading");
    const qs = await generatePool(rnd, usedQs);
    // Reset everything
    setPool(shuffle(qs));
    setPoolIdx(0);
    setSelected(null); setSF(false);
    setRS(0); setQA(0); setQC(0);
    setStreak(0); setCombo(0); setLog([]);
    setShU(false); setElU(false); setFrU(false); setHiU(false);
    setElim(null); setHintA(false); setFrozen(false);
    setTimeLeft(maxTime);
    setScreen("playing");
  };

  const newGame = async () => {
    setRound(1); setTotalEP(0); setBankEP(0);
    setUsedQs([]);
    setUpgrades({timer:0,crit:0,streak:0,shield:0,eliminate:0,freeze:0,multiplier:0,hint:0});
    await beginRound(1, null);
  };

  const nextRound = async () => {
    const nr = round + 1; setRound(nr);
    await beginRound(nr, null);
  };

  const buy = (id) => {
    const upg = BASE_UPGRADES.find(u=>u.id===id);
    const lv  = upgrades[id];
    const cost = Math.round(upg.cost * Math.pow(1.6, lv));
    if (bankEP >= cost && lv < upg.maxLevel) {
      setBankEP(b=>b-cost);
      setUpgrades(u=>({...u,[id]:u[id]+1}));
    }
  };

  const doElim = () => {
    if (elimUsed || !upgrades.eliminate || selected!==null || !q) return;
    const w = [0,1,2,3].filter(i=>i!==q.answer);
    setElim(w[Math.floor(Math.random()*w.length)]); setElU(true);
  };
  const doFreeze = () => {
    if (freezeUsed || !upgrades.freeze || selected!==null) return;
    setFrozen(true); setFrU(true);
    setTimeout(()=>setFrozen(false), 5000);
  };
  const doHint = () => {
    if (hintUsed || !upgrades.hint || selected!==null || !q) return;
    setHintA(true); setHiU(true);
    setTimeout(()=>setHintA(false), 1800);
  };

  // ─── LOADING ──────────────────────────────────────────────────────────────
  if (screen === "loading") return (
    <><style>{CSS}</style><FloatingParticles/><LoadingScreen round={round}/></>
  );

  // ─── MENU ─────────────────────────────────────────────────────────────────
  if (screen === "menu") return (
    <>
      <style>{CSS}</style>
      <Analytics />
      <FloatingParticles/>
      <div className="grid-bg" style={{minHeight:"100vh",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:24,position:"relative",zIndex:1}}>
        <div style={{textAlign:"center",maxWidth:520}}>
          <div style={{marginBottom:8,marginTop:-8}}>
            <div style={{
              fontFamily:"'Syne',sans-serif",
              fontSize:72,
              fontWeight:800,
              letterSpacing:"-0.03em",
              lineHeight:1,
              background:"linear-gradient(135deg, #00d4ff 0%, #39ff7a 50%, #00d4ff 100%)",
              backgroundSize:"200% 200%",
              WebkitBackgroundClip:"text",
              WebkitTextFillColor:"transparent",
              backgroundClip:"text",
              animation:"titleFloat 4s ease-in-out infinite, shimmer 3s linear infinite",
              textShadow:"none",
              filter:"drop-shadow(0 0 32px rgba(0,212,255,0.4))",
              paddingBottom:4,
            }}>Sci Blitz</div>
            <style>{`
              @keyframes shimmer {
                0% { background-position: 0% 50%; }
                50% { background-position: 100% 50%; }
                100% { background-position: 0% 50%; }
              }
            `}</style>
          </div>
          <div style={{display:"none"}}>
            <img
              src="data:image/png;base64,"
              alt="Sci Blitz - The Science Knowledge Game"
              style={{width:"100%",maxWidth:520,display:"block",margin:"0 auto",filter:"drop-shadow(0 0 32px rgba(0,212,255,0.35)) drop-shadow(0 0 16px rgba(57,255,122,0.2))",animation:"titleFloat 4s ease-in-out infinite"}}
            />
          </div>

          <p style={{color:"#8899aa",fontSize:15,marginBottom:32,lineHeight:1.7}}>
            Race the clock. Answer as many questions<br/>as you can before time runs out.
          </p>

          {/* How it works */}
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:10,marginBottom:32}}>
            {[
              ["⏱","Timed Round","Answer questions continuously until time expires"],
              ["⚡","Earn EP","Score more with streaks, crits & speed bonuses"],
              ["✨","Upgrade","Spend EP to boost your lab between rounds"],
            ].map(([icon,title,desc])=>(
              <div key={title} style={{background:"rgba(255,255,255,0.03)",border:"1px solid rgba(255,255,255,0.07)",borderRadius:10,padding:"14px 12px",textAlign:"center"}}>
                <div style={{fontSize:22,marginBottom:6}}>{icon}</div>
                <div style={{fontFamily:"'Space Mono',monospace",fontSize:10,color:"#aaa",letterSpacing:"0.06em",marginBottom:4}}>{title}</div>
                <div style={{fontSize:11,color:"#8899aa",lineHeight:1.4}}>{desc}</div>
              </div>
            ))}
          </div>

          <div style={{display:"flex",gap:12,justifyContent:"center",marginBottom:28,flexWrap:"wrap"}}>
            {[["Physics ⚛️","#00d4ff"],["Chemistry 🧪","#ff6b35"],["Biology 🧬","#39ff7a"]].map(([t,c])=>(
              <div key={t} style={{padding:"5px 16px",borderRadius:20,background:`${c}0e`,border:`1px solid ${c}38`,fontSize:13,fontWeight:600,color:c}}>{t}</div>
            ))}
          </div>

          {highScore>0 && (
            <div style={{fontFamily:"'Space Mono',monospace",fontSize:13,color:"#ffbe0b",marginBottom:20}}>
              ★ HIGH SCORE: {highScore.toLocaleString()} EP
            </div>
          )}

          <button onClick={newGame} style={{
            background:"linear-gradient(135deg,#00d4ff,#39ff7a)",
            border:"none",borderRadius:14,padding:"18px 52px",
            fontSize:18,fontWeight:800,color:"#080c14",
            cursor:"pointer",letterSpacing:"0.06em",
            boxShadow:"0 0 50px rgba(0,212,255,0.3)",
            fontFamily:"'Syne',sans-serif",
          }}>
            START EXPERIMENT
          </button>
          <div style={{marginTop:16,fontSize:11,color:"#6677aa",fontFamily:"'Space Mono',monospace"}}>
            {ROUND_BASE_TIME}s per round to start · difficulty scales · infinite rounds
          </div>

          {/* ── Support link ── */}
          <div style={{marginTop:36,padding:"16px 20px",background:"rgba(255,255,255,0.025)",border:"1px solid rgba(255,255,255,0.07)",borderRadius:12,maxWidth:380,width:"100%",textAlign:"center",marginLeft:"auto",marginRight:"auto"}}>
            <div style={{fontSize:12,color:"#9aa0b0",lineHeight:1.7,marginBottom:12}}>
              Sci Blitz is completely free to play. If you're enjoying it and want to see more projects like this, you can support the work ☕
            </div>
            <a
              href="https://buymeacoffee.com/rs_science"
              target="_blank"
              rel="noopener noreferrer"
              style={{
                display:"inline-flex",alignItems:"center",gap:8,
                background:"#FFDD00",color:"#000",
                fontFamily:"'Syne',sans-serif",fontWeight:800,fontSize:13,
                padding:"10px 20px",borderRadius:8,
                textDecoration:"none",letterSpacing:"0.04em",
                boxShadow:"0 0 20px rgba(255,221,0,0.2)",
                transition:"opacity 0.15s",
              }}
              onMouseOver={e=>e.currentTarget.style.opacity="0.85"}
              onMouseOut={e=>e.currentTarget.style.opacity="1"}
            >
              ☕ Buy me a coffee
            </a>
          </div>
        </div>
      </div>
    </>
  );

  // ─── PLAYING ──────────────────────────────────────────────────────────────
  if (screen === "playing" && q) {
    const tc = TOPIC_COLORS[q.topic] || "#00d4ff";
    const ti = TOPIC_ICONS[q.topic]  || "🔬";
    const pct = timeLeft / maxTime;
    const urgent = pct < 0.2 && !frozen;

    return (
      <>
        <style>{CSS}</style>
        <FloatingParticles/>
        <ScorePop pops={pops}/>
        <div className="grid-bg" style={{minHeight:"100vh",display:"flex",flexDirection:"column",alignItems:"center",padding:"18px 16px 32px",position:"relative",zIndex:1}}>

          {/* ── Top HUD ── */}
          <div style={{width:"100%",maxWidth:620,marginBottom:8}}>
            {/* Row 1: Round / EP / Combo */}
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
              <div>
                <div style={{fontFamily:"'Space Mono',monospace",fontSize:9,color:"#8899aa",letterSpacing:"0.2em"}}>ROUND</div>
                <div style={{fontFamily:"'Space Mono',monospace",fontSize:22,fontWeight:700,color:"#00d4ff",lineHeight:1}}>{String(round).padStart(2,"0")}</div>
              </div>

              <div style={{textAlign:"center"}}>
                {combo>=3 && (
                  <div style={{fontFamily:"'Space Mono',monospace",fontSize:12,color:"#ff6b35",animation:"urgentPulse 0.7s infinite",marginBottom:2}}>
                    🔥 ×{combo} COMBO
                  </div>
                )}
                <div style={{fontFamily:"'Space Mono',monospace",fontSize:10,color:"#8899aa",letterSpacing:"0.15em"}}>
                  {qCorrect}/{qAnswered} correct
                </div>
              </div>

              <div style={{textAlign:"right"}}>
                <div style={{fontFamily:"'Space Mono',monospace",fontSize:9,color:"#8899aa",letterSpacing:"0.2em"}}>ENERGY</div>
                <div style={{fontFamily:"'Space Mono',monospace",fontSize:22,fontWeight:700,color:"#ffbe0b",lineHeight:1}}>{totalEP.toLocaleString()}</div>
              </div>
            </div>

            {/* Row 2: Timer bar */}
            <RoundTimerBar timeLeft={timeLeft} maxTime={maxTime} frozen={frozen}/>
          </div>

          {/* ── Question card ── */}
          <div style={{
            width:"100%",maxWidth:620,
            background:"rgba(255,255,255,0.028)",
            border:`1px solid ${tc}25`, borderLeft:`4px solid ${tc}`,
            borderRadius:14,padding:"18px 20px",marginBottom:12,marginTop:22,
            animation:"slideIn 0.2s ease",
            boxShadow:`0 0 30px ${tc}0a`,
          }}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
              <div style={{fontFamily:"'Space Mono',monospace",fontSize:10,color:tc,letterSpacing:"0.12em",fontWeight:700}}>
                {ti} {q.topic.toUpperCase()} · {"★".repeat(q.difficulty)}{"☆".repeat(3-q.difficulty)}
              </div>
            </div>
            <p style={{fontSize:16,fontWeight:700,lineHeight:1.55,color:"#f0f0f0"}}>{q.q}</p>
          </div>

          {/* ── Options ── */}
          <div style={{width:"100%",maxWidth:620,display:"flex",flexDirection:"column",gap:8,marginBottom:12}}>
            {q.options.map((opt,i)=>{
              let cls = "opt";
              if (i===eliminated)                            cls += " elim";
              else if (showFeedback && i===q.answer)         cls += " correct";
              else if (selected===i && i!==q.answer)         cls += " wrong";
              else if (hintActive && i===q.answer && !selected) cls += " hint";
              return (
                <button key={i} className={cls}
                  disabled={selected!==null || i===eliminated}
                  onClick={()=>answer(i)}>
                  <span style={{fontFamily:"'Space Mono',monospace",fontSize:10,color:"#7788aa",marginRight:12}}>
                    {["A","B","C","D"][i]}
                  </span>
                  {opt}
                </button>
              );
            })}
          </div>

          {/* ── Explanation (brief) ── */}
          {showFeedback && q.explanation && (
            <div style={{
              width:"100%",maxWidth:620,
              background:"rgba(255,255,255,0.02)",border:"1px solid rgba(255,255,255,0.06)",
              borderRadius:9,padding:"10px 14px",
              fontSize:12,color:"#aab0bc",lineHeight:1.5,
              animation:"fadeUp 0.25s ease",marginBottom:10,
            }}>
              <span style={{fontFamily:"'Space Mono',monospace",fontSize:9,letterSpacing:"0.1em",color:"#00d4ff"}}>WHY · </span>
              {q.explanation}
            </div>
          )}

          {/* ── Power-ups ── */}
          {(upgrades.eliminate>0||upgrades.freeze>0||upgrades.hint>0) && (
            <div style={{display:"flex",gap:7,flexWrap:"wrap",justifyContent:"center"}}>
              {upgrades.eliminate>0 && <button className={`pup ${!elimUsed&&!selected?"on":"off"}`} onClick={doElim}>🎯 Filter</button>}
              {upgrades.freeze>0    && <button className={`pup ${!freezeUsed&&!selected?"on":"off"}`} onClick={doFreeze}>❄️ Freeze</button>}
              {upgrades.hint>0      && <button className={`pup ${!hintUsed&&!selected?"on":"off"}`} onClick={doHint}>💡 Probe</button>}
            </div>
          )}
        </div>
      </>
    );
  }

  // ─── SUMMARY (wrong answers review) ──────────────────────────────────────
  if (screen === "summary") {
    const wrongAnswers = roundLog.filter(r => !r.correct && !r.shielded && r.question);
    const tc = TOPIC_COLORS;

    return (
      <>
        <style>{CSS}</style>
        <FloatingParticles/>
        <div className="grid-bg" style={{minHeight:"100vh",padding:"22px 16px 44px",display:"flex",flexDirection:"column",alignItems:"center",position:"relative",zIndex:1}}>
          <div style={{width:"100%",maxWidth:620}}>

            {/* Header */}
            <div style={{textAlign:"center",marginBottom:24}}>
              <div style={{fontFamily:"'Space Mono',monospace",fontSize:10,color:"#00d4ff",letterSpacing:"0.3em",marginBottom:5}}>
                ROUND {round} COMPLETE
              </div>
              <h2 style={{fontSize:30,fontWeight:800,letterSpacing:"-0.02em",marginBottom:2}}>Round Summary</h2>
              <div style={{fontSize:13,color:"#8899aa",marginTop:8}}>
                {qCorrect}/{qAnswered} correct · {roundScore.toLocaleString()} EP earned
              </div>
            </div>

            {wrongAnswers.length === 0 ? (
              <div style={{
                textAlign:"center",padding:"32px 20px",
                background:"rgba(57,255,122,0.05)",
                border:"1px solid rgba(57,255,122,0.2)",
                borderRadius:14,marginBottom:24,
              }}>
                <div style={{fontSize:32,marginBottom:10}}>🎯</div>
                <div style={{fontFamily:"'Space Mono',monospace",fontSize:13,color:"#39ff7a",fontWeight:700}}>PERFECT ROUND</div>
                <div style={{fontSize:13,color:"#8899aa",marginTop:6}}>No incorrect answers!</div>
              </div>
            ) : (
              <>
                <div style={{fontFamily:"'Space Mono',monospace",fontSize:10,color:"#ff4757",letterSpacing:"0.15em",marginBottom:12}}>
                  MISSED QUESTIONS · {wrongAnswers.length}
                </div>
                <div style={{display:"flex",flexDirection:"column",gap:12,marginBottom:24}}>
                  {wrongAnswers.map((r,i) => {
                    const color = tc[r.topic] || "#aaa";
                    return (
                      <div key={i} style={{
                        background:"rgba(255,255,255,0.028)",
                        border:`1px solid ${color}25`,
                        borderLeft:`4px solid ${color}`,
                        borderRadius:12,padding:"16px 18px",
                      }}>
                        {/* Topic tag */}
                        <div style={{fontFamily:"'Space Mono',monospace",fontSize:9,color:color,letterSpacing:"0.12em",fontWeight:700,marginBottom:8}}>
                          {TOPIC_ICONS[r.topic] || "🔬"} {r.topic?.toUpperCase()}
                        </div>

                        {/* Question */}
                        <div style={{fontSize:14,fontWeight:600,color:"#ddd",lineHeight:1.5,marginBottom:12}}>
                          {r.question}
                        </div>

                        {/* Answers */}
                        <div style={{display:"flex",flexDirection:"column",gap:5,marginBottom:12}}>
                          {r.options?.map((opt, oi) => {
                            const isCorrect = oi === r.correctIdx;
                            const isChosen  = oi === r.chosenIdx;
                            let bg = "rgba(255,255,255,0.03)";
                            let border = "rgba(255,255,255,0.07)";
                            let textColor = "#555";
                            if (isCorrect) { bg="rgba(57,255,122,0.08)"; border="#39ff7a55"; textColor="#39ff7a"; }
                            if (isChosen && !isCorrect) { bg="rgba(255,71,87,0.08)"; border="#ff475755"; textColor="#ff4757"; }
                            return (
                              <div key={oi} style={{
                                background:bg, border:`1px solid ${border}`,
                                borderRadius:8, padding:"8px 12px",
                                fontSize:13, color:textColor,
                                display:"flex", alignItems:"center", gap:8,
                              }}>
                                <span style={{fontFamily:"'Space Mono',monospace",fontSize:9,opacity:0.5}}>
                                  {["A","B","C","D"][oi]}
                                </span>
                                <span style={{flex:1}}>{opt}</span>
                                {isCorrect && <span style={{fontSize:11}}>✓</span>}
                                {isChosen && !isCorrect && <span style={{fontSize:11}}>✗</span>}
                              </div>
                            );
                          })}
                        </div>

                        {/* Explanation */}
                        {r.explanation && (
                          <div style={{
                            background:"rgba(255,255,255,0.02)",
                            border:"1px solid rgba(255,255,255,0.06)",
                            borderRadius:8,padding:"10px 12px",
                            fontSize:12,color:"#aab0bc",lineHeight:1.6,
                          }}>
                            <span style={{fontFamily:"'Space Mono',monospace",fontSize:9,letterSpacing:"0.1em",color:"#00d4ff"}}>WHY · </span>
                            {r.explanation}
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              </>
            )}

            <button onClick={()=>setScreen("shop")} style={{
              width:"100%",background:"linear-gradient(135deg,#00d4ff,#39ff7a)",
              border:"none",borderRadius:14,padding:17,
              fontSize:17,fontWeight:800,color:"#080c14",
              cursor:"pointer",letterSpacing:"0.06em",
              fontFamily:"'Syne',sans-serif",
              boxShadow:"0 0 28px rgba(0,212,255,0.2)",
            }}>
              CONTINUE TO UPGRADE LAB →
            </button>
          </div>
        </div>
      </>
    );
  }

  // ─── SHOP (between rounds) ────────────────────────────────────────────────
  if (screen === "shop") {
    // Build topic breakdown from log
    const byTopic = {};
    roundLog.forEach(r=>{
      if (!byTopic[r.topic]) byTopic[r.topic] = {correct:0,total:0};
      byTopic[r.topic].total++;
      if (r.correct) byTopic[r.topic].correct++;
    });

    return (
      <>
        <style>{CSS}</style>
        <FloatingParticles/>
        <div className="grid-bg" style={{minHeight:"100vh",padding:"22px 16px 44px",display:"flex",flexDirection:"column",alignItems:"center",position:"relative",zIndex:1}}>
          <div style={{width:"100%",maxWidth:620}}>

            {/* Header */}
            <div style={{textAlign:"center",marginBottom:20}}>
              <div style={{fontFamily:"'Space Mono',monospace",fontSize:10,color:"#00d4ff",letterSpacing:"0.3em",marginBottom:5}}>
                ROUND {round} COMPLETE
              </div>
              <h2 style={{fontSize:34,fontWeight:800,letterSpacing:"-0.02em",marginBottom:2}}>Upgrade Lab</h2>

              {/* Stats */}
              <div style={{display:"flex",gap:16,justifyContent:"center",marginTop:14,flexWrap:"wrap"}}>
                {[
                  [qAnswered,           "ANSWERED",    "#e0e0e0"],
                  [qCorrect,            "CORRECT",     "#39ff7a"],
                  [roundScore.toLocaleString(), "ROUND EP", "#ffbe0b"],
                  [bankEP.toLocaleString(),  "AVAILABLE",  "#00d4ff"],
                ].map(([v,l,c])=>(
                  <div key={l} style={{textAlign:"center"}}>
                    <div style={{fontFamily:"'Space Mono',monospace",fontSize:20,color:c,fontWeight:700}}>{v}</div>
                    <div style={{fontSize:10,color:"#8899aa"}}>{l}</div>
                  </div>
                ))}
              </div>
            </div>

            {/* Topic breakdown */}
            {Object.keys(byTopic).length > 0 && (
              <div style={{display:"flex",gap:8,marginBottom:16,justifyContent:"center",flexWrap:"wrap"}}>
                {Object.entries(byTopic).map(([topic,{correct,total}])=>{
                  const c = TOPIC_COLORS[topic]||"#aaa";
                  const pct = total>0 ? Math.round(correct/total*100) : 0;
                  return (
                    <div key={topic} style={{
                      display:"flex",alignItems:"center",gap:7,
                      background:`${c}0d`,border:`1px solid ${c}33`,
                      borderRadius:8,padding:"6px 12px",
                    }}>
                      <span>{TOPIC_ICONS[topic]}</span>
                      <div>
                        <div style={{fontFamily:"'Space Mono',monospace",fontSize:10,color:c,fontWeight:700}}>{pct}%</div>
                        <div style={{fontSize:10,color:"#8899aa"}}>{correct}/{total}</div>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}

            {/* Upgrades */}
            <div style={{display:"flex",flexDirection:"column",gap:8,marginBottom:20}}>
              {BASE_UPGRADES.map(upg=>(
                <UpgradeCard key={upg.id} upgrade={upg} level={upgrades[upg.id]} points={bankEP} onBuy={buy}/>
              ))}
            </div>

            <button onClick={nextRound} style={{
              width:"100%",background:"linear-gradient(135deg,#00d4ff,#39ff7a)",
              border:"none",borderRadius:14,padding:17,
              fontSize:17,fontWeight:800,color:"#080c14",
              cursor:"pointer",letterSpacing:"0.06em",
              fontFamily:"'Syne',sans-serif",
              boxShadow:"0 0 28px rgba(0,212,255,0.2)",
            }}>
              ROUND {round+1} → {maxTime + 0}s
            </button>
            <button onClick={()=>setScreen("menu")} style={{
              width:"100%",marginTop:8,background:"transparent",
              border:"1px solid rgba(255,255,255,0.07)",borderRadius:14,padding:13,
              fontSize:13,fontWeight:600,color:"#8899aa",
              cursor:"pointer",fontFamily:"'Syne',sans-serif",
            }}>
              Return to Menu
            </button>
          </div>
        </div>
      </>
    );
  }

  return null;
}
